import os, csv, re
from datetime import date

LOGDIR = '/app/logs'
REF = date(2025, 8, 12)
from datetime import timedelta
last7 = REF - timedelta(days=6)
last30 = REF - timedelta(days=29)
month1 = date(REF.year, REF.month, 1)

SEVS = ['ERROR', 'WARNING', 'INFO']
pat = re.compile(r'\[(ERROR|WARNING|INFO)\]')
fname_re = re.compile(r'^(\d{4})-(\d{2})-(\d{2})_.*\.log$')

periods = ['today', 'last_7_days', 'last_30_days', 'month_to_date', 'total']
counts = {p: {s: 0 for s in SEVS} for p in periods}

for fn in os.listdir(LOGDIR):
    m = fname_re.match(fn)
    if not m:
        continue
    d = date(int(m.group(1)), int(m.group(2)), int(m.group(3)))
    local = {s: 0 for s in SEVS}
    with open(os.path.join(LOGDIR, fn), encoding='utf-8', errors='replace') as f:
        for line in f:
            mm = pat.search(line)
            if mm:
                local[mm.group(1)] += 1
    for s in SEVS:
        c = local[s]
        counts['total'][s] += c
        if d == REF:
            counts['today'][s] += c
        if last7 <= d <= REF:
            counts['last_7_days'][s] += c
        if last30 <= d <= REF:
            counts['last_30_days'][s] += c
        if month1 <= d <= REF:
            counts['month_to_date'][s] += c

with open('/app/summary.csv', 'w', newline='') as f:
    w = csv.writer(f)
    w.writerow(['period', 'severity', 'count'])
    for p in periods:
        for s in SEVS:
            w.writerow([p, s, counts[p][s]])
print(open('/app/summary.csv').read())

